class Employee:
    def __init__(self, employee_id, employee_name, manager_id):
        self.employee_id = employee_id
        self.employee_name = employee_name
        self.manager_id = manager_id
        self.level = None
        self.subordinate_count = None
        self.manager_chain = None

class Organization:
    def __init__(self, employees):
        self.employees = {employee.employee_id: employee for employee in employees}
        self.ceo = next((employee for employee in employees if employee.manager_id is None), None)

    def calculate_levels(self):
        def dfs(employee, level):
            employee.level = level
            for e in self.employees.values():
                if e.manager_id == employee.employee_id:
                    dfs(e, level + 1)

        dfs(self.ceo, 1)

    def calculate_subordinate_count(self):
        def dfs(employee):
            count = 0
            for e in self.employees.values():
                if e.manager_id == employee.employee_id:
                    count += 1 + dfs(e)
            employee.subordinate_count = count
            return count

        dfs(self.ceo)

    def calculate_manager_chain(self):
        def dfs(employee):
            if employee.manager_id is None:
                employee.manager_chain = None
            else:
                manager = self.employees[employee.manager_id]
                employee.manager_chain = manager.employee_name + (">" + manager.manager_chain if manager.manager_chain else "")
                dfs(manager)

        for employee in self.employees.values():
            dfs(employee)

    def print_results(self):
        print("Hierarchy Levels:")
        for employee in self.employees.values():
            print(f"{employee.employee_id} | {employee.employee_name} | {employee.level}")

        print("\nSubordinate Count:")
        for employee in self.employees.values():
            print(f"{employee.employee_id} | {employee.employee_name} | {employee.subordinate_count}")

        print("\nManager Chain:")
        for employee in self.employees.values():
            print(f"{employee.employee_id} | {employee.employee_name} | {employee.manager_chain}")

