            employee.subordinate_count = count
            return count

        dfs([e for e in self.employees if e.manager_id is None][0].employee_id)

    def calculate_manager_chain(self):
        def dfs(employee_id):
            employee = self.employee_map[employee_id]
            if employee.manager_id is None:
                employee.manager_chain = None
            else:
                manager = self.employee_map[employee.manager_id]
                employee.manager_chain = manager.employee_name + (">" + manager.manager_chain if manager.manager_chain else "")
                dfs(manager.employee_id)

        dfs([e for e in self.employees if e.manager_id is None][0].employee_id)
