class Employee:
    def __init__(self, employee_id, employee_name, manager_id):
        self.employee_id = employee_id
        self.employee_name = employee_name
        self.manager_id = manager_id
        self.subordinates = []
        self.level = None
        self.manager_chain = None

class Organization:
    def __init__(self):
        self.employees = {}
        self.ceo = None

    def add_employee(self, employee_id, employee_name, manager_id):
        employee = Employee(employee_id, employee_name, manager_id)
        self.employees[employee_id] = employee
        if manager_id is not None:
            self.employees[manager_id].subordinates.append(employee)
        else:
            self.ceo = employee

    def calculate_levels(self):
        self.ceo.level = 1
        self.calculate_levels_recursive(self.ceo, 2)

    def calculate_levels_recursive(self, employee, level):
        employee.level = level
        for subordinate in employee.subordinates:
            self.calculate_levels_recursive(subordinate, level + 1)

    def calculate_subordinate_counts(self):
        for employee in self.employees.values():
            employee.subordinate_count = self.calculate_subordinate_count_recursive(employee)

    def calculate_subordinate_count_recursive(self, employee):
        count = 0
        for subordinate in employee.subordinates:
            count += 1 + self.calculate_subordinate_count_recursive(subordinate)
        return count

    def calculate_manager_chains(self):
        for employee in self.employees.values():
            employee.manager_chain = self.calculate_manager_chain_recursive(employee)

    def calculate_manager_chain_recursive(self, employee):
        if employee.manager_id is None:
            return None
        manager_chain = self.employees[employee.manager_id].employee_name
        manager = self.employees[employee.manager_id]
        while manager.manager_id is not None:
            manager_chain = self.employees[manager.manager_id].employee_name + '>' + manager_chain
            manager = self.employees[manager.manager_id]
        return manager_chain

    def print_hierarchy_levels(self):
        print("Hierarchy Levels:")
        for employee in self.employees.values():
            print(f"{employee.employee_id} | {employee.employee_name} | {employee.level}")

    def print_subordinate_counts(self):
        print("\nSubordinate Count:")
        for employee in self.employees.values():
            print(f"{employee.employee_id} | {employee.employee_name} | {employee.subordinate_count}")

    def print_manager_chains(self):
        print("\nManager Chain:")
        for employee in self.employees.values():
            if employee.manager_chain is None:
                print(f"{employee.employee_id} | {employee.employee_name} | NULL")
            else:
                print(f"{employee.employee_id} | {employee.employee_name} | {employee.manager_chain}")


