    def __init__(self):
        self.employees = {}

    def add_employee(self, employee_id, employee_name, manager_id):
        self.employees[employee_id] = Employee(employee_id, employee_name, manager_id)

    def calculate_levels(self):
        def dfs(employee_id, level):
            if self.employees[employee_id].level is not None:
                return
            self.employees[employee_id].level = level
            for emp_id, employee in self.employees.items():
                if employee.manager_id == employee_id:
                    dfs(emp_id, level + 1)

        dfs(list(self.employees.keys())[0], 1)

    def calculate_subordinate_count(self):
        def dfs(employee_id):
            count = 0
            for emp_id, employee in self.employees.items():
                if employee.manager_id == employee_id:
                    count += 1 + dfs(emp_id)
            return count

        for employee_id in self.employees:
            self.employees[employee_id].subordinate_count = dfs(employee_id)

    def calculate_manager_chain(self):
        def dfs(employee_id):
            if self.employees[employee_id].manager_id is None:
                return ""
            manager_id = self.employees[employee_id].manager_id
            return dfs(manager_id) + " > " + self.employees[manager_id].employee_name if dfs(manager_id) else self.employees[manager_id].employee_name

        for employee_id in self.employees:
            self.employees[employee_id].manager_chain = dfs(employee_id)

    def print_results(self):
        print("Hierarchy Levels:")
        for employee_id in self.employees:
            print(f"{self.employees[employee_id].employee_id} | {self.employees[employee_id].employee_name} | {self.employees[employee_id].level}")
        print("\nSubordinate Count:")
        for employee_id in self.employees:
            print(f"{self.employees[employee_id].employee_id} | {self.employees[employee_id].employee_name} | {self.employees[employee_id].subordinate_count}")
        print("\nManager Chain:")
        for employee_id in self.employees:
            print(f"{self.employees[employee_id].employee_id} | {self.employees[employee_id].employee_name} | {self.employees[employee_id].manager_chain}")

