import pandas as pd

def analyze_organizational_hierarchy(df):
    # Tierarchy Levels
    df['level'] = 0
    df.loc[df['manager_id'] == 'NULL', 'level'] = 1
    for _ in range(10):
        max_level = df['level'].max()
        if max_level == 0:
            break
        for index, row in df.iterrows():
            if row['level'] == 0:
                manager_level = df.loc[df['employee_id'] == row['manager_id'], 'level']
                if not manager_level.empty:
                    df.loc[index, 'level'] = manager_level.values[0] + 1
    print("Tierarchy Levels:")
    print(df[['employee_id', 'employee_name', 'level']])

    # Subordinate Count
    df['subordinate_count'] = 0
    for index, row in df.iterrows():
        if row['level'] > 1:
            subordinate_count = len(df[(df['manager_id'] == row['employee_id'])])
            df.loc[index, 'subordinate_count'] = subordinate_count
            for _, subordinate_row in df.iterrows():
                if subordinate_row['manager_id'] == row['employee_id']:
                    df.loc[index, 'subordinate_count'] += subordinate_row['subordinate_count']
    print("\nSubordinate Count:")
    print(df[['employee_id', 'employee_name', 'subordinate_count']])

    # Managing Chain
    df['managing_chain'] = ''
    for index, row in df.iterrows():
        if row['level'] > 1:
            manager_id = row['manager_id']
            managing_chain = ''
            while manager_id != 'NULL':
                manager_name = df.loc[df['employee_id'] == manager_id, 'employee_name'].values[0]
                managing_chain = manager_name + ' -> ' + managing_chain
                manager_id = df.loc[df['employee_id'] == manager_id, 'manager_id'].values[0]
            df.loc[index, 'managing_chain'] = managing_chain[:-3]
    print("\nManaging Chain:")
    print(df[['employee_id', 'employee_name', 'managing_chain']])

