        if employee:
            level = 0
            while employee.manager:
                level += 1
                employee = employee.manager
            return level
        return None

    def get_direct_reports(self, name):
        employee = self.employees.get(name)
        if employee:
            return [report.name for report in employee.direct_reports]
        return None

    def get_management_chain(self, name):
        employee = self.employees.get(name)
        if employee:
            chain = []
            while employee:
                chain.append(employee.name)
                employee = employee.manager
            return chain[::-1]
        return None

    def get_ceo(self):
        return self.ceo.name if self.ceo else None

