class Employee:
    def __init__(self, name, manager=None):
        self.name = name
        self.manager = manager

class Company:
    def __init__(self):
        self.employees = {}

    def add_employee(self, name, manager_name=None):
        if name not in self.employees:
            if manager_name is None:
                self.employees[name] = Employee(name)
            else:
                if manager_name in self.employees:
                    self.employees[name] = Employee(name, self.employees[manager_name])
                else:
                    raise ValueError("Manager not found")
        else:
            raise ValueError("Employee already exists")

    def get_level(self, name):
        if name in self.employees:
            level = 0
            employee = self.employees[name]
            while employee.manager is not None:
                level += 1
                employee = employee.manager
            return level
        else:
            raise ValueError("Employee not found")

    def get_manager_name(self, name):
        if name in self.employees:
            employee = self.employees[name]
            if employee.manager is not None:
                return employee.manager.name
            else:
                return None
        else:
            raise ValueError("Employee not found")

    def get_employees_under_manager(self, manager_name):
        employees_under_manager = []
        for name, employee in self.employees.items():
            if employee.manager is not None and employee.manager.name == manager_name:
                employees_under_manager.append(name)
        return employees_under_manager

