class Employee:
    def __init__(self, name, manager=None):
        self.name = name
        self.manager = manager
        self.direct_reports = []

    def add_direct_report(self, employee):
        self.direct_reports.append(employee)

    def get_level(self):
        if self.manager is None:
            return 1
        else:
            return self.manager.get_level() + 1

    def get_manager_name(self):
        if self.manager is None:
            return None
        else:
            return self.manager.name

    def get_direct_reports_names(self):
        return [employee.name for employee in self.direct_reports]

class Company:
    def __init__(self):
        self.employees = {}

    def add_employee(self, name, manager_name=None):
        if name not in self.employees:
            self.employees[name] = Employee(name)
        if manager_name is not None and manager_name in self.employees:
            self.employees[manager_name].add_direct_report(self.employees[name])
            self.employees[name].manager = self.employees[manager_name]

    def get_employee_level(self, name):
        if name in self.employees:
            return self.employees[name].get_level()
        else:
            return None

    def get_employee_manager(self, name):
        if name in self.employees:
            return self.employees[name].get_manager_name()
        else:
            return None

    def get_employee_direct_reports(self, name):
        if name in self.employees:
            return self.employees[name].get_direct_reports_names()
        else:
            return None

